import { Component, OnInit, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormBuilder, ReactiveFormsModule, Validators } from '@angular/forms';
import { Router, RouterLink } from '@angular/router';
import { CentsPipe } from '../../shared/cents.pipe';
import { Unit, User } from '../../core/models';

@Component({
  selector: 'app-lease-new',
  standalone: true,
  imports: [CommonModule, ReactiveFormsModule, RouterLink, CentsPipe],
  templateUrl: './lease-new.component.html',
  styleUrl: './lease-new.component.css',
})
export class LeaseNewComponent implements OnInit {
  readonly loading = signal(false);
  readonly error = signal('');

  readonly units = signal<Unit[]>([
    { id: 'u1', number: '101', bedrooms: 1, rentCents: 120000 },
    { id: 'u2', number: '102', bedrooms: 2, rentCents: 180000 },
    { id: 'u3', number: '201', bedrooms: 2, rentCents: 190000 },
    { id: 'u4', number: '202', bedrooms: 3, rentCents: 240000 },
  ]);

  readonly tenants = signal<User[]>([
    { id: 't1', name: 'Alex Rivera', email: 'tenant1@demo', role: 'tenant' },
    { id: 't2', name: 'Bailey Chen', email: 'tenant2@demo', role: 'tenant' },
    { id: 't3', name: 'Casey Morgan', email: 'tenant3@demo', role: 'tenant' },
  ]);

  readonly form = this.fb.group({
    unitId: ['', [Validators.required]],
    tenantId: ['', [Validators.required]],
    startsOn: ['', [Validators.required]],
    endsOn: ['', [Validators.required]],
    rentDollars: [0, [Validators.required, Validators.min(0)]],
    dueDay: [1, [Validators.required, Validators.min(1), Validators.max(31)]],
  });

  constructor(
    private fb: FormBuilder,
    private router: Router,
  ) {}

  ngOnInit(): void {
    // Prefill rent from the chosen unit's monthly rent.
    this.form.controls.unitId.valueChanges.subscribe((id) => {
      const unit = this.units().find((u) => u.id === id);
      if (unit) {
        this.form.controls.rentDollars.setValue(unit.rentCents / 100);
      }
    });
  }

  unitLabel(u: Unit): string {
    const dollars = (u.rentCents / 100).toLocaleString('en-US', {
      style: 'currency',
      currency: 'USD',
    });
    return `${u.number} · ${u.bedrooms} bed · ${dollars}`;
  }

  submit(): void {
    if (this.form.invalid) {
      this.form.markAllAsTouched();
      return;
    }
    const raw = this.form.getRawValue();
    const payload = {
      unitId: raw.unitId,
      tenantId: raw.tenantId,
      startsOn: raw.startsOn,
      endsOn: raw.endsOn,
      rentCents: Math.round((Number(raw.rentDollars) || 0) * 100),
      dueDay: Number(raw.dueDay),
    };
    this.loading.set(true);
    // Mock persistence — no real API in the portal mockup.
    console.log('Create lease', payload);
    setTimeout(() => {
      this.loading.set(false);
      this.router.navigate(['/leases']);
    }, 450);
  }
}
